using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.ComputeLimit;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.ComputeLimit.Tests.Samples
{
    public class Sample1_GettingStarted
    {
        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task ListFeaturesAsync()
        {
            #region Snippet:Azure_ResourceManager_ComputeLimit_ListFeatures
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            AzureLocation location = AzureLocation.EastUS;
            ComputeLimitFeatureCollection features = subscription.GetComputeLimitFeatures(location);

            await foreach (ComputeLimitFeatureResource feature in features)
            {
                Console.WriteLine($"Feature: {feature.Data.Name}, ProvisioningState: {feature.Data.Properties?.ProvisioningState}");
            }
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task EnableFeatureAsync()
        {
            #region Snippet:Azure_ResourceManager_ComputeLimit_EnableFeature
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            AzureLocation location = AzureLocation.EastUS;
            string featureName = "SharedQuota";
            ComputeLimitFeatureResource feature = await subscription.GetComputeLimitFeatures(location).GetAsync(featureName);

            ArmOperation<OperationStatusResult> operation = await feature.EnableAsync(WaitUntil.Completed);
            Console.WriteLine($"Enable operation status: {operation.Value.Status}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task DisableFeatureAsync()
        {
            #region Snippet:Azure_ResourceManager_ComputeLimit_DisableFeature
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            AzureLocation location = AzureLocation.EastUS;
            string featureName = "SharedQuota";
            ComputeLimitFeatureResource feature = await subscription.GetComputeLimitFeatures(location).GetAsync(featureName);

            ArmOperation<OperationStatusResult> operation = await feature.DisableAsync(WaitUntil.Completed);
            Console.WriteLine($"Disable operation status: {operation.Value.Status}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task AddGuestSubscriptionAsync()
        {
            #region Snippet:Azure_ResourceManager_ComputeLimit_AddGuestSubscription
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            AzureLocation location = AzureLocation.EastUS;
            string featureName = "SharedQuota";
            ComputeLimitFeatureResource feature = await subscription.GetComputeLimitFeatures(location).GetAsync(featureName);

            ComputeLimitGuestSubscriptionCollection guestSubscriptions = feature.GetComputeLimitGuestSubscriptions();
            string guestSubscriptionId = "<guest-subscription-id>";
            ComputeLimitGuestSubscriptionData data = new ComputeLimitGuestSubscriptionData();
            ArmOperation<ComputeLimitGuestSubscriptionResource> createOp =
                await guestSubscriptions.CreateOrUpdateAsync(WaitUntil.Completed, guestSubscriptionId, data);
            Console.WriteLine($"Added guest subscription: {createOp.Value.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task ListVmFamiliesAsync()
        {
            #region Snippet:Azure_ResourceManager_ComputeLimit_ListVmFamilies
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            AzureLocation location = AzureLocation.EastUS;
            ComputeLimitVmFamilyCollection vmFamilies = subscription.GetComputeLimitVmFamilies(location);

            await foreach (ComputeLimitVmFamilyResource vmFamily in vmFamilies)
            {
                Console.WriteLine($"VM Family: {vmFamily.Data.Name}");
            }
            #endregion
        }
    }
}
```

